import { Component, Element, h, Listen, Prop, State } from '@stencil/core';
import { isHigherThanTablet } from '../../utils/breakpoint.utils';
import { propagateToSlot } from '../../utils/utils';
import { ButtonSize } from '../wdpr-button/wdpr-button';

@Component({
  tag: 'wdpr-landscape-secondary-card',
  shadow: true,
})
export class WdprLandscapeSecondaryCard {
  @Element() el: HTMLWdprLandscapeSecondaryCardElement;

  @State() _buttonSize: ButtonSize = 'medium';

  @Prop() headline: string;
  @Prop() body: string;

  @Prop() src: string;
  @Prop({ attribute: 'a11y-alt' }) a11yAlt: string;

  /*
   * If consumer doesn't want the default resizing sizes
   * for button based on viewport, they can set this to true
   */
  @Prop() avoidButtonResize: boolean = false;

  @Listen('resize', { target: 'window' })
  handleResize() {
    // For sizes higher than tablet design team wants to set a button size to medium
    if (this.avoidButtonResize) return;

    this._buttonSize = isHigherThanTablet() ? 'medium' : 'small';
    this._syncButtonSlot();
  }

  componentDidLoad() {
    if (this.avoidButtonResize) return;
    this._syncButtonSlot();
  }

  private _syncButtonSlot = () => {
    const slotEl = this.el.shadowRoot?.querySelector('slot[name="button"]') as HTMLSlotElement;
    propagateToSlot(slotEl, 'size', this._buttonSize, 'wdpr-button');
  };

  private _onSlotButtonChange = () => {
    if (this.avoidButtonResize) return;
    this._syncButtonSlot();
  };

  render() {
    return (
      <article class={baseClasses}>
        <figure class={mediaWrapperClasses}>
          <wdpr-media src={this.src} alt={this.a11yAlt} aspect="landscape" objectFit="cover" landscapeRatio="16:9" />
        </figure>
        <div class="flex flex-col items-start self-stretch px-100 gap-150">
          <div class="flex flex-col items-start self-stretch gap-050">
            <span class={headlineClasses}>{this.headline}</span>
            <p class={bodyClasses}>{this.body}</p>
          </div>
          <div class="flex flex-col items-start self-stretch gap-150">
            <slot name="text-link" />

            <slot name="button" onSlotchange={this._onSlotButtonChange} />
          </div>
        </div>
      </article>
    );
  }
}

const baseClasses = 'flex flex-col items-start gap-150 w-full transition-all';
const mediaWrapperClasses = 'w-full elevation-small-soft lg:elevation-medium-soft rounded-300 overflow-hidden';
const headlineClasses = `text-heading-xsmall transition-all font-heading-alt leading-heading-xsmall tracking--05 line-clamp-2
  md:text-heading-small md:leading-heading-small
  lg:text-heading-medium lg:leading-heading-medium
  xl:text-heading-large xl:leading-heading-large`;
const bodyClasses = `text-body-medium transition-all font-body-default leading-body-medium tracking-default line-clamp-2
  xl:text-body-large xl:leading-body-large`;
